import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

const Home = () => {
    const [songs, setSongs] = useState([]);

    useEffect(() => {
        axios.get('http://localhost:5000/api/songs').then(res => setSongs(res.data));
    }, []);

    return (
        <div style={{ padding: '20px', maxWidth: '1200px', margin: '0 auto' }}>
            <h2 style={{ marginBottom: '20px' }}>Khám phá âm nhạc mới</h2>
            {/* GRID LAYOUT - KHÁC BIỆT VỚI PROFILE */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '25px' }}>
                {songs.map(song => (
                    <div key={song._id} style={{ background: '#fff', padding: '15px', borderRadius: '15px', boxShadow: '0 4px 10px rgba(0,0,0,0.1)' }}>
                        <img src={`http://localhost:5000${song.imageUrl}`} style={{ width: '100%', height: '180px', borderRadius: '10px', objectFit: 'cover' }} alt="" />
                        <h4 style={{ margin: '15px 0 5px 0' }}>{song.title}</h4>
                        {/* Nhấn vào tên ca sĩ để sang trang Profile với List Layout */}
                        <Link to={`/profile/${song.userId}`} style={{ color: '#1db954', textDecoration: 'none', fontSize: '14px' }}>
                           👤 {song.artist}
                        </Link>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default Home;
